// Kernel function for the simulation
__kernel void macro_xs_lookup_kernel(
    Inputs in,
    int max_num_nucs,
    __global const int * num_nucs,
    __global const double * concs,
    __global const double * unionized_energy_array,
    __global const int * index_grid,
    __global const NuclideGridPoint * nuclide_grid,
    __global const int * mats,
    __global int * verification_array
)
{
    // Get the work item ID
    int idx = get_global_id(0);

    // Set the initial seed value
    uint64_t seed = STARTING_SEED;

    // Forward seed to lookup index (we need 2 samples per lookup)
    // Note: In OpenCL, we don't have fast_forward_LCG directly.
    // We'll generate random numbers sequentially for simplicity here.
    // For true performance, a more robust PRNG with state management would be needed.
    uint64_t current_seed = seed;
    for(int i = 0; i < 2 * idx; ++i) {
        current_seed = (LCG_A * current_seed + LCG_C) % LCG_M;
    }


    // Randomly pick an energy and material for the particle
    double p_energy = LCG_random_double_kernel_wrapper(&current_seed);

    // Pick material (simplified for kernel, assumes a fixed distribution or requires passing it)
    // For now, let's use a simple random pick for material, assuming 12 materials
    int mat = (int)(LCG_random_double_kernel_wrapper(&current_seed) * 12.0); 

    double macro_xs_vector[5] = {0};

    // Perform macroscopic Cross Section Lookup
    calculate_macro_xs_kernel_wrapper(
            p_energy,        // Sampled neutron energy (in lethargy)
            mat,             // Sampled material type index neutron is in
            in.n_isotopes,   // Total number of isotopes in simulation
            in.n_gridpoints, // Number of gridpoints per isotope in simulation
            num_nucs,        // 1-D array with number of nuclides per material
            concs,           // Flattened 2-D array with concentration of each nuclide in each material
            unionized_energy_array, // 1-D Unionized energy array
            index_grid,      // Flattened 2-D grid holding indices into nuclide grid for each unionized energy level
            nuclide_grid,    // Flattened 2-D grid holding energy levels and XS_data for all nuclides in simulation
            mats,            // Flattened 2-D array with nuclide indices defining composition of each type of material
            macro_xs_vector, // 1-D array with result of the macroscopic cross section (5 different reaction channels)
            in.grid_type,    // Lookup type (nuclide, hash, or unionized)
            in.hash_bins,    // Number of hash bins used (if using hash lookup type)
            max_num_nucs     // Maximum number of nuclides present in any material
            );

    // For verification, and to prevent the compiler from optimizing
    // all work out, we interrogate the returned macro_xs_vector array
    // to find its maximum value index, then increment the verification
    // value by that index.
    double max = -1.0;
    int max_idx = 0;
    for (int j = 0; j < 5; j++) {
        if (macro_xs_vector[j] > max) {
            max = macro_xs_vector[j];
            max_idx = j;
        }
    }
    verification_array[idx] = max_idx + 1;
}

